@param minInactivityPeriod_    Minimum inactivity period (seconds).
@param maxInactivityPeriod_    Hard ceiling on inactivity period (seconds).
@param maxCheckUpkeepSize_     Max wallets scanned per checkUpkeep (off-chain).
